-- =============================================
-- Natural Glowra: Seed RBAC Data + Admin User
-- =============================================
-- Run on VPS:
--   psql -U postgres -d natural_glowra -f db/migrations/2026-03-31-seed-glowra-rbac-and-admin.sql
--
-- This is IDEMPOTENT — safe to run multiple times (ON CONFLICT DO NOTHING).
-- =============================================

BEGIN;

-- ── 1. PERMISSIONS ────────────────────────────

-- ── 2. ROLES ──────────────────────────────────

-- ── 3. ROLE ↔ PERMISSION MAPPINGS ─────────────

-- ── 4. RESET SEQUENCES ────────────────────────
SELECT setval('public.permissions_id_seq', GREATEST((SELECT MAX(id) FROM permissions), 1), true);
SELECT setval('public.roles_id_seq', GREATEST((SELECT MAX(id) FROM roles), 1), true);

-- ── 5. ADMIN USER ─────────────────────────────
-- Email:    admin@naturalglowra.com
-- Password: admin123
VALUES (
  'Admin',
  'Glowra',
  'admin@naturalglowra.com',
  '$2b$10$I2jvV5Pd30K6mK0VtXzatOnSLDZM.3k7i1pA4WzgNkMqQL9ObhWdK',
  12,
  'active',
  false,
  true
)
ON CONFLICT (email) DO NOTHING;

-- ── 6. LINK ADMIN USER TO SUPER ADMIN ROLE ────
-- The RBAC system uses user_roles junction table (not users.role_id)
SELECT u.id, 12, NOW()
FROM public.users u
WHERE u.email = 'admin@naturalglowra.com'
  AND NOT EXISTS (
    SELECT 1 FROM public.user_roles ur
    WHERE ur.user_id = u.id AND ur.role_id = 12
  );

COMMIT;

-- ── VERIFY ────────────────────────────────────
SELECT 'permissions' AS table_name, count(*) AS row_count FROM permissions
UNION ALL
SELECT 'roles', count(*) FROM roles
UNION ALL
SELECT 'role_permissions', count(*) FROM role_permissions
UNION ALL
SELECT 'admin_user', count(*) FROM users WHERE email = 'admin@naturalglowra.com';
