INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (16, 'Purchase Manager', 'Procurement officer managing suppliers, purchase orders, quotations, and cost optimization. Requires approval for POs.', '{}', false, '2025-12-13 03:54:11.069745', '2026-03-09 23:30:37.349852', 'purchase-manager', 600, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (17, 'Accounts', 'Finance user handling invoices, payments, ledgers, bank reconciliation, and financial reports. No access to CRM/inventory editing.', '{}', false, '2025-12-13 03:54:11.069745', '2026-03-09 23:30:37.349852', 'accounts', 700, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (9, 'Viewer', 'Read-only analyst access. Can view reports, dashboards, and summaries but cannot create/edit/delete any data.', '{}', true, '2025-12-11 11:22:56.205195', '2026-03-09 23:30:37.349852', 'viewer', 100, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (19, 'HR Manager', 'Human resources manager for employee profiles, attendance, payroll, leave approval, and performance evaluation.', '{}', false, '2025-12-13 03:54:11.069745', '2026-03-09 23:30:37.349852', 'hr-manager', 650, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (20, 'Delivery Partner', 'Logistics user for delivery management, route tracking, POD updates, and delivery status management. Limited to assigned deliveries only.', '{}', false, '2025-12-13 03:54:11.069745', '2026-03-09 23:30:37.349852', 'delivery-partner', 300, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (21, 'Brand Manager', 'Marketing module manager for campaigns, banners, coupons, ads tracking, and customer segmentation. No finance/inventory access.', '{}', false, '2025-12-13 03:54:11.069745', '2026-03-09 23:30:37.349852', 'brand-manager', 550, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (22, 'Customer Account', 'MLM member account with profile management, wallet/points view, order history, referral system, and support ticket creation.', '{}', false, '2025-12-13 03:54:11.069745', '2026-03-09 23:30:37.349852', 'customer-account', 200, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (23, 'Supplier Account', 'Supplier portal access for profile updates, PO management, invoice uploads, and payment tracking. Limited to supplier-specific data.', '{}', false, '2025-12-13 03:54:11.069745', '2026-03-09 23:30:37.349852', 'supplier-account', 250, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (36, 'Recruiter', 'HR Recruiter for job posting, applicant screening, interview scheduling, and candidate pipeline management. Cannot approve final hiring or salary.', '{}', false, '2025-12-13 04:13:20.877891', '2026-03-09 23:30:37.349852', 'recruiter', 640, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (37, 'Job Applicant', 'Candidate account for job applications, profile management, resume upload, interview tracking, and offer letter download. Limited to own data only.', '{}', false, '2025-12-13 04:13:20.877891', '2026-03-09 23:30:37.349852', 'job-applicant', 150, true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.roles (id, name, description, permissions, is_system_role, created_at, updated_at, slug, priority, is_active) VALUES (38, 'Sales Team Leader', 'CRM supervisor for lead assignment, team monitoring, escalation handling, and performance tracking. Cannot approve sales orders or edit prices/inventory.', '{}', false, '2025-12-13 04:13:20.877891', '2026-03-09 23:30:37.349852', 'sales-team-leader', 520, true) ON CONFLICT (id) DO NOTHING;
